Javascript.logic:
var opt = Services.getValue(NewAddressForService.dataBinding);

Services.setValue( NewAddL4.dataBinding, "");

if( 'ACK' == opt && null != solNode )
{	var ad4N = solNode.selectSingleNode("./ContactDetails/Address/Line[4]");
	if( 'ACK' == opt && null != ad4N)
	{ Services.setValue(NewAddL4.dataBinding, XML.getNodeTextContent( ad4N ));
	}
}
else if( 'ADDR' == opt && null != defNode )
{	Services.setValue(NewAddL4.dataBinding, XML.getNodeTextContent( defNode.selectSingleNode("./ContactDetails/Address/Line[4]")));
}
